# ── ANALYSIS 1: Momentum ranking across multiple lookback periods ──────────────
from utils.momentum import rank_by_momentum, calculate_momentum

prices = tsla["Close"].dropna().tolist()
print(f"Total monthly prices available: {len(prices)}")

momentum_results = {}
for period in [1, 3, 6, 12, 24]:
    try:
        mom = calculate_momentum(prices, period=period)
        momentum_results[period] = mom
        print(f"  {period:2d}-month momentum: {mom:+.1f}%")
    except ValueError as e:
        print(f"  {period:2d}-month: {e}")
